ALLOWED_DOMAINS = ['internal-resources.company.com', 'cdn.company.com']
MAX_RESOURCE_SIZE = 100 * 1024 * 1024  # 100MB


def verify_url_safety(url):
    """Verify URL is from allowed domains and uses HTTPS"""
    from urllib.parse import urlparse
    
    parsed = urlparse(url)
    
    if parsed.scheme != 'https':
        raise ValueError(f"Only HTTPS URLs are allowed: {url}")
    
    if parsed.hostname not in ALLOWED_DOMAINS:
        raise ValueError(f"Domain not in allowed list: {parsed.hostname}")
    
    return True


def verify_file_integrity(filepath, expected_sha256, expected_size):
    """Verify downloaded file integrity using SHA256 hash and size"""
    if not os.path.exists(filepath):
        return False
    
    file_size = os.path.getsize(filepath)
    if file_size != expected_size:
        print(f"Size mismatch: expected {expected_size}, got {file_size}")
        return False
    
    if file_size > MAX_RESOURCE_SIZE:
        raise ValueError(f"File size exceeds maximum allowed: {file_size}")
    
    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    
    computed_hash = sha256_hash.hexdigest()
    if computed_hash != expected_sha256:
        print(f"Hash mismatch: expected {expected_sha256}, got {computed_hash}")
        return False
    
    return True


def secure_download(url, destination, expected_sha256, expected_size, max_retries=3):
    """Securely download file with integrity verification"""
    verify_url_safety(url)
    
    context = ssl.create_default_context()
    context.check_hostname = True
    context.verify_mode = ssl.CERT_REQUIRED
    
    for attempt in range(max_retries):
        try:
            print(f"Downloading {url} (attempt {attempt + 1}/{max_retries})...")
            
            req = urllib.request.Request(url, headers={'User-Agent': 'InternalLibraryInstaller/1.0'})
            
            with urllib.request.urlopen(req, context=context, timeout=30) as response:
                content_length = response.getheader('Content-Length')
                if content_length and int(content_length) > MAX_RESOURCE_SIZE:
                    raise ValueError(f"Resource too large: {content_length} bytes")
                
                with open(destination, 'wb') as out_file:
                    downloaded = 0
                    while True:
                        chunk = response.read(8192)
                        if not chunk:
                            break
                        downloaded += len(chunk)
                        if downloaded > MAX_RESOURCE_SIZE:
                            raise ValueError("Download exceeded maximum size")
                        out_file.write(chunk)
            
            if verify_file_integrity(destination, expected_sha256, expected_size):
                print(f"Successfully downloaded and verified {destination}")
                return True
            else:
                print(f"Integrity check failed for {destination}")
                if os.path.exists(destination):
                    os.remove(destination)
                
        except Exception as e:
            print(f"Download attempt {attempt + 1} failed: {e}")
            if os.path.exists(destination):
                os.remove(destination)
            
            if attempt == max_retries - 1:
                raise
    
    return False


def get_config_dir():
    """Get platform-appropriate configuration directory"""
    if sys.platform == 'win32':
        base = os.environ.get('APPDATA', os.path.expanduser('~'))
        config_dir = os.path.join(base, 'InternalLibrary')
    elif sys.platform == 'darwin':
        config_dir = os.path.expanduser('~/Library/Application Support/InternalLibrary')
    else:
        config_dir = os.path.expanduser('~/.config/internallibrary')
    
    return config_dir


def get_data_dir():
    """Get platform-appropriate data directory"""
    if sys.platform == 'win32':
        base = os.environ.get('LOCALAPPDATA', os.path.expanduser('~'))
        data_dir = os.path.join(base, 'InternalLibrary', 'data')
    elif sys.platform == 'darwin':
        data_dir = os.path.expanduser('~/Library/Application Support/InternalLibrary/data')
    else:
        data_dir = os.path.expanduser('~/.local/share/internallibrary')
    
    return data_dir


def setup_directories():
    """Create necessary configuration and data directories"""
    config_dir = get_config_dir()
    data_dir = get_data_dir()
    
    for directory in [config_dir, data_dir]:
        Path(directory).mkdir(parents=True, exist_ok=True)
        
        if sys.platform != 'win32':
            os.chmod(directory, 0o700)
        
        print(f"Created directory: {directory}")
    
    return config_dir, data_dir


def download_resources(data_dir):
    """Download and verify all required resources"""
    for filename, info in RESOURCE_MANIFEST.items():
        destination = os.path.join(data_dir, filename)
        
        if os.path.exists(destination):
            if verify_file_integrity(destination, info['sha256'], info['size']):
                print(f"Resource {filename} already exists and is valid")
                continue
            else:
                print(f"Existing {filename} is invalid, re-downloading...")
                os.remove(destination)
        
        try:
            secure_download(
                info['url'],
                destination,
                info['sha256'],
                info['size']
            )
        except Exception as e:
            print(f"Warning: Failed to download {filename}: {e}")
            print("Installation will continue, but some features may not work.")


def setup_environment_config(config_dir, data_dir):
    """Create environment configuration file"""
    env_config = {
        'INTERNAL_LIB_CONFIG_DIR': config_dir,
        'INTERNAL_LIB_DATA_DIR': data_dir,
        'INTERNAL_LIB_VERSION': '1.0.0'
    }
    
    config_file = os.path.join(config_dir, 'environment.json')
    
    with open(config_file, 'w') as f:
        json.dump(env_config, f, indent=2)
    
    if sys.platform != 'win32':
        os.chmod(config_file, 0o600)
    
    print(f"Created environment configuration: {config_file}")
    
    shell_config = os.path.join(config_dir, 'env.sh')
    with open(shell_config, 'w') as f:
        f.write("#!/bin/bash\n")
        for key, value in env_config.items():
            f.write(f'export {key}="{value}"\n')
    
    if sys.platform != 'win32':
        os.chmod(shell_config, 0o700)
    
    print("\nEnvironment variables configured:")
    for key, value in env_config.items():
        print(f"  {key}={value}")
    
    print(f"\nTo load environment variables, run:")
    print(f"  source {shell_config}")


